import { keymap } from 'prosemirror-keymap'
import { Fragment, Slice } from 'prosemirror-model'
import { schema as basicSchema } from 'prosemirror-schema-basic'
import { Plugin, PluginKey, TextSelection } from 'prosemirror-state'
import { Decoration, DecorationSet } from 'prosemirror-view'

/**
 * Detect @ mention at cursor position by scanning real ProseMirror positions.
 * This avoids string-index to doc-position conversion bugs around hard breaks.
 */
export function getMentionStateAtSelection(selection: TextSelection): MentionState {
    if (!selection.empty) {
        return null
    }

    const { doc } = selection.$from
    const cursorPos = selection.from
    let mentionFrom: number | null = null
    let query = ''

    for (let pos = cursorPos; pos > 0; pos--) {
        const prevPos = pos - 1
        const char = doc.textBetween(prevPos, pos, '\n', '\n')

        if (char === '\n') {
            break
        }

        if (char === '@') {
            mentionFrom = prevPos
            break
        }

        if (char) {
            query = char + query
            continue
        }

        // Stop at text block boundaries (e.g., paragraph splits).
        const prevParent = doc.resolve(prevPos).parent
        const currParent = doc.resolve(pos).parent
        if (prevParent !== currParent) {
            break
        }
    }

    if (mentionFrom === null) {
        return null
    }

    return {
        active: true,
        from: mentionFrom,
        to: cursorPos,
        query,
    }
}

// Coords type for ProseMirror coordsAtPos
type Coords = { left: number; right: number; top: number; bottom: number }

// Use basic ProseMirror schema directly
export const editorSchema = basicSchema

// Mention state interface
export type MentionState = {
    active: boolean
    from: number // pos of "@"
    to: number // current cursor
    query: string
} | null

export const mentionKey = new PluginKey<MentionState>('mention')

// Mention detection plugin
export function mentionPlugin(opts: { onChange: (state: MentionState, coords?: Coords) => void }): Plugin {
    return new Plugin<MentionState>({
        key: mentionKey,
        state: {
            init: (): MentionState => null,
            apply(tr, prev, _oldState, newState): MentionState {
                const sel = newState.selection as TextSelection
                if (!sel.empty) return null // Only handle cursor selection

                return getMentionStateAtSelection(sel)
            },
        },

        props: {
            decorations(state) {
                const mention = mentionKey.getState(state)
                if (!mention || !mention.active) return null

                return DecorationSet.create(state.doc, [
                    Decoration.inline(mention.from, mention.to, {
                        class: 'pm-mention-active',
                    }),
                ])
            },
        },

        view(editorView) {
            // Check initial state immediately when view is created
            const initialState = mentionKey.getState(editorView.state)

            if (initialState && initialState.active) {
                // Get coordinates for the "@" character position (from), not cursor (to)
                try {
                    const domCoords = editorView.coordsAtPos(initialState.from) as Coords
                    opts.onChange(initialState, domCoords)
                } catch (e) {
                    // In test environment, coordsAtPos might fail - call onChange without coordinates
                    opts.onChange(initialState, undefined)
                }
            }

            return {
                update(view, prevState) {
                    const prev = mentionKey.getState(prevState)
                    const curr = mentionKey.getState(view.state)

                    // Only trigger onChange if state actually changed
                    if (prev === curr) {
                        return
                    }

                    if (curr && curr.active) {
                        // Get coordinates for the "@" character position (from), not cursor (to)
                        try {
                            const domCoords = view.coordsAtPos(curr.from) as Coords
                            opts.onChange(curr, domCoords)
                        } catch (e) {
                            // In test environment, coordsAtPos might fail - call onChange without coordinates
                            opts.onChange(curr, undefined)
                        }
                    } else {
                        opts.onChange(null)
                    }
                },
            }
        },
    })
}

// Helper function to apply suggestion selection
export function applySuggestion(view: any, suggestion: string) {
    const mentionState = mentionKey.getState(view.state)
    if (!mentionState) return

    const { from, to } = mentionState
    const docSize = view.state.doc.content.size
    const newText = suggestion + ' '

    // Safety check: ensure positions are within document bounds
    if (from < 0 || to > docSize || from > to) {
        console.warn('Invalid mention position range:', { from, to, docSize })
        return
    }

    // Guard against stale mention state. Only replace when the range still starts at '@'.
    if (from + 1 > docSize || view.state.doc.textBetween(from, from + 1, '\n', '\n') !== '@') {
        console.warn('Ignoring stale mention range:', { from, to, docSize })
        return
    }

    const tr = view.state.tr.insertText(newText, from, to)
    const newPos = Math.min(from + newText.length, tr.doc.content.size)

    view.dispatch(tr.setSelection(TextSelection.create(tr.doc, newPos)))
    view.focus()
}

// Suggestion interaction interface for keyboard plugin
interface SuggestionInteraction {
    suggestions: Array<any> // Accept any suggestion type as long as it has text property
    selectedIndex: number
    selectSuggestion: (suggestion: any) => void
    hideSuggestions: () => void
    navigateSelection: (direction: 'up' | 'down') => void
}

// Comprehensive keyboard handling plugin that integrates mention state with suggestion UI
export function keyboardPlugin(opts: {
    onSubmit?: () => void
    disabled?: () => boolean
    getValue?: () => string
    getSuggestionState?: () => SuggestionInteraction | null
    onOpenImagePicker?: () => void
