import { schema as basicSchema } from 'prosemirror-schema-basic'
import { EditorState, TextSelection } from 'prosemirror-state'
import { describe, expect, test, vi } from 'vitest'

import { applySuggestion, getMentionStateAtSelection, mentionKey, mentionPlugin } from './PromptEditor.plugins'

describe('PromptEditor mention range detection', () => {
    test('tracks mention range after two hard breaks (Shift+Enter)', () => {
        const hardBreak = basicSchema.nodes.hard_break.create()
        const paragraph = basicSchema.node('paragraph', null, [
            basicSchema.text('apple'),
            hardBreak,
            hardBreak,
            basicSchema.text('tree @rea'),
        ])
        const doc = basicSchema.node('doc', null, [paragraph])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeTruthy()
        expect(mentionState?.query).toBe('rea')

        // Verify that the replacement starts exactly at '@', not at previous word chars.
        if (mentionState) {
            expect(doc.textBetween(mentionState.from, mentionState.from + 1, '\n', '\n')).toBe('@')
            expect(doc.textBetween(mentionState.from - 2, mentionState.from, '\n', '\n')).toBe('e ')
        }
    })

    test('applySuggestion only replaces @query segment after hard breaks', () => {
        const hardBreak = basicSchema.nodes.hard_break.create()
        const paragraph = basicSchema.node('paragraph', null, [
            basicSchema.text('apple'),
            hardBreak,
            hardBreak,
            basicSchema.text('tree @rea'),
        ])
        const doc = basicSchema.node('doc', null, [paragraph])
        const plugin = mentionPlugin({ onChange: () => {} })

        let state = EditorState.create({
            schema: basicSchema,
            doc,
            plugins: [plugin],
        })

        state = state.apply(state.tr.setSelection(TextSelection.atEnd(state.doc)))

        const focus = vi.fn()
        const view = {
            state,
            dispatch(tr: any) {
                this.state = this.state.apply(tr)
            },
            focus,
        }

        applySuggestion(view, 'github.com/sourcegraph/sourcegraph')

        expect(view.state.doc.textBetween(0, view.state.doc.content.size, '\n', '\n')).toBe(
            'apple\n\ntree github.com/sourcegraph/sourcegraph '
        )
        expect(focus).toHaveBeenCalled()
    })

    test('applySuggestion is a no-op when mention range is stale', () => {
        const paragraph = basicSchema.node('paragraph', null, [basicSchema.text('tree hello')])
        const doc = basicSchema.node('doc', null, [paragraph])
        const state = EditorState.create({ schema: basicSchema, doc })
        const dispatch = vi.fn()
        const focus = vi.fn()
        const view = { state, dispatch, focus }

        const staleMentionSpy = vi.spyOn(mentionKey, 'getState').mockReturnValue({
            active: true,
            from: 1,
            to: 4,
            query: 'ree',
        })

        try {
            applySuggestion(view, 'github.com/sourcegraph/sourcegraph')
            expect(dispatch).not.toHaveBeenCalled()
            expect(focus).not.toHaveBeenCalled()
            expect(view.state.doc.textBetween(0, view.state.doc.content.size, '\n', '\n')).toBe('tree hello')
        } finally {
            staleMentionSpy.mockRestore()
        }
    })

    // Single-line @-mention detection
    test('detects @ mention at start of a single-line paragraph', () => {
        const paragraph = basicSchema.node('paragraph', null, [basicSchema.text('@repo')])
        const doc = basicSchema.node('doc', null, [paragraph])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeTruthy()
        expect(mentionState?.query).toBe('repo')
        // The '@' character should be at the start of the doc text
        if (mentionState) {
            expect(doc.textBetween(mentionState.from, mentionState.from + 1, '\n', '\n')).toBe('@')
        }
    })

    test('detects @ mention after whitespace in a single line', () => {
        const paragraph = basicSchema.node('paragraph', null, [basicSchema.text('hello @world')])
        const doc = basicSchema.node('doc', null, [paragraph])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeTruthy()
        expect(mentionState?.query).toBe('world')
        if (mentionState) {
            expect(doc.textBetween(mentionState.from, mentionState.from + 1, '\n', '\n')).toBe('@')
        }
    })

    test('returns null when no @ is present', () => {
        const paragraph = basicSchema.node('paragraph', null, [basicSchema.text('hello world')])
        const doc = basicSchema.node('doc', null, [paragraph])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeNull()
    })

    test('detects @ with empty query (cursor right after @)', () => {
        const paragraph = basicSchema.node('paragraph', null, [basicSchema.text('hello @')])
        const doc = basicSchema.node('doc', null, [paragraph])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeTruthy()
        expect(mentionState?.query).toBe('')
        if (mentionState) {
            expect(doc.textBetween(mentionState.from, mentionState.from + 1, '\n', '\n')).toBe('@')
        }
    })

    test('returns null when selection is not empty (range selection)', () => {
        const paragraph = basicSchema.node('paragraph', null, [basicSchema.text('hello @world')])
        const doc = basicSchema.node('doc', null, [paragraph])
        // Select from position 1 to 5 (a range)
        const selection = TextSelection.create(doc, 1, 5) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeNull()
    })

    // Multi-line / multi-paragraph @-mention detection
    test('detects @ mention in second paragraph (multi-paragraph doc)', () => {
        const para1 = basicSchema.node('paragraph', null, [basicSchema.text('first paragraph')])
        const para2 = basicSchema.node('paragraph', null, [basicSchema.text('second @mention')])
        const doc = basicSchema.node('doc', null, [para1, para2])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeTruthy()
        expect(mentionState?.query).toBe('mention')
        if (mentionState) {
            expect(doc.textBetween(mentionState.from, mentionState.from + 1, '\n', '\n')).toBe('@')
        }
    })

    test('does not cross paragraph boundaries when looking for @', () => {
        // First paragraph ends with '@cross', second paragraph has text after cursor.
        // The cursor is at start of second paragraph — should NOT find the @ in first para.
        const para1 = basicSchema.node('paragraph', null, [basicSchema.text('first @cross')])
        const para2 = basicSchema.node('paragraph', null, [basicSchema.text('second')])
        const doc = basicSchema.node('doc', null, [para1, para2])
        // Place cursor at the very start of the second paragraph's text
        // Para1 occupies positions 1..13 (1 opening + 12 chars + closing), doc positions:
        // 0: doc open, 1: para1 open, 2..13: text, 14: para1 close, 15: para2 open, 16..21: text, 22: para2 close
        const para2Start = para1.nodeSize + 2 // skip doc open + para1 + para2 open
        const selection = TextSelection.create(doc, para2Start) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        // Cursor is at start of "second" with no @ in second paragraph before cursor
        expect(mentionState).toBeNull()
    })

    test('detects @ at start of second paragraph', () => {
        const para1 = basicSchema.node('paragraph', null, [basicSchema.text('first paragraph')])
        const para2 = basicSchema.node('paragraph', null, [basicSchema.text('@start')])
        const doc = basicSchema.node('doc', null, [para1, para2])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeTruthy()
        expect(mentionState?.query).toBe('start')
        if (mentionState) {
            expect(doc.textBetween(mentionState.from, mentionState.from + 1, '\n', '\n')).toBe('@')
        }
    })

    test('anchor position is derived from ProseMirror state (not flattened string) after hard break', () => {
        // This test specifically verifies that the anchor (from) position for the @ sign
        // is correct even when there are hard breaks before it, which would cause wrong
        // offsets if we used a flattened string representation.
        const hardBreak = basicSchema.nodes.hard_break.create()
        const paragraph = basicSchema.node('paragraph', null, [
            basicSchema.text('line one text'),
            hardBreak,
            basicSchema.text('@query'),
        ])
        const doc = basicSchema.node('doc', null, [paragraph])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeTruthy()
        expect(mentionState?.query).toBe('query')

        // The 'from' position must point exactly to '@' in the ProseMirror document
        if (mentionState) {
            const charAtFrom = doc.textBetween(mentionState.from, mentionState.from + 1, '\n', '\n')
            expect(charAtFrom).toBe('@')

            // Verify 'to' is the cursor position (end of doc text)
            expect(mentionState.to).toBe(selection.from)

            // The query length should match (to - from - 1) since from points to '@'
            expect(mentionState.to - mentionState.from - 1).toBe(mentionState.query.length)
        }
