            expect(dispatch).not.toHaveBeenCalled()
            expect(focus).not.toHaveBeenCalled()
            expect(view.state.doc.textBetween(0, view.state.doc.content.size, '\n', '\n')).toBe('tree hello')
        } finally {
            staleMentionSpy.mockRestore()
        }
    })

    // Single-line @-mention detection
    test('detects @ mention at start of a single-line paragraph', () => {
        const paragraph = basicSchema.node('paragraph', null, [basicSchema.text('@repo')])
        const doc = basicSchema.node('doc', null, [paragraph])
        const selection = TextSelection.atEnd(doc) as TextSelection

        const mentionState = getMentionStateAtSelection(selection)
        expect(mentionState).toBeTruthy()
        expect(mentionState?.query).toBe('repo')
